import { Question } from '../../types';

// ============================================================================
// MICROSOFT DYNAMICS OPERATOR QUESTIONS
// ============================================================================

// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msDynProfessionalQuestions: Question[] = [
  { id: 'ms-dyn-prof-1', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-navigation', type: 'multiple-choice', content: { es: 'Necesita acceder rápidamente al registro de un cliente en Dynamics 365 pero no recuerda en qué módulo se encuentra. ¿Cuál es la forma más eficiente de localizarlo?', en: 'You need to quickly access a customer record in Dynamics 365 but don\'t remember which module it\'s in. What is the most efficient way to locate it?', fr: 'Vous devez accéder rapidement au dossier d\'un client dans Dynamics 365 mais ne vous souvenez plus dans quel module il se trouve. Quelle est la façon la plus efficace de le localiser ?' }, options: [{ id: 'a', text: { es: 'Navegar módulo por módulo hasta encontrar el registro del cliente', en: 'Navigate module by module until finding the customer record', fr: 'Naviguer module par module jusqu\'à trouver le dossier client' }, value: 0 }, { id: 'b', text: { es: 'Utilizar la barra de búsqueda global en la parte superior para buscar por nombre o número de cliente', en: 'Use the global search bar at the top to search by customer name or number', fr: 'Utiliser la barre de recherche globale en haut pour chercher par nom ou numéro de client' }, value: 100 }, { id: 'c', text: { es: 'Pedir a un compañero que le indique dónde está el registro', en: 'Ask a colleague to tell you where the record is', fr: 'Demander à un collègue de vous indiquer où se trouve le dossier' }, value: 25 }, { id: 'd', text: { es: 'Cerrar sesión y volver a entrar al sistema para que aparezca en la página de inicio', en: 'Log out and log back in so it appears on the home page', fr: 'Se déconnecter et se reconnecter pour qu\'il apparaisse sur la page d\'accueil' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-dyn-prof-2', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-transactions', type: 'multiple-choice', content: { es: 'Al registrar una orden de venta en Dynamics 365, el sistema muestra un error indicando que el producto seleccionado no tiene inventario disponible. ¿Qué debe hacer primero?', en: 'When entering a sales order in Dynamics 365, the system shows an error indicating that the selected product has no available inventory. What should you do first?', fr: 'Lors de la saisie d\'une commande de vente dans Dynamics 365, le système affiche une erreur indiquant que le produit sélectionné n\'a pas de stock disponible. Que devez-vous faire en premier ?' }, options: [{ id: 'a', text: { es: 'Verificar en el módulo de inventario el stock actual y las órdenes de compra pendientes antes de tomar cualquier acción', en: 'Check current stock and pending purchase orders in the inventory module before taking any action', fr: 'Vérifier le stock actuel et les commandes d\'achat en attente dans le module d\'inventaire avant de prendre toute action' }, value: 100 }, { id: 'b', text: { es: 'Eliminar la orden de venta y decirle al cliente que no hay producto', en: 'Delete the sales order and tell the customer there is no product', fr: 'Supprimer la commande et dire au client qu\'il n\'y a pas de produit' }, value: 0 }, { id: 'c', text: { es: 'Forzar la transacción cambiando manualmente la cantidad de inventario', en: 'Force the transaction by manually changing the inventory quantity', fr: 'Forcer la transaction en modifiant manuellement la quantité de stock' }, value: 0 }, { id: 'd', text: { es: 'Cambiar el producto por uno similar que sí tenga inventario sin consultar al cliente', en: 'Switch the product to a similar one that has inventory without consulting the customer', fr: 'Changer le produit pour un similaire en stock sans consulter le client' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-dyn-prof-3', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-reporting', type: 'multiple-choice', content: { es: 'Su supervisor le pide un reporte de todas las facturas pendientes de cobro de los últimos 30 días. ¿Cuál es la mejor forma de generarlo en Dynamics 365?', en: 'Your supervisor asks for a report of all outstanding invoices from the last 30 days. What is the best way to generate it in Dynamics 365?', fr: 'Votre superviseur vous demande un rapport de toutes les factures impayées des 30 derniers jours. Quelle est la meilleure façon de le générer dans Dynamics 365 ?' }, options: [{ id: 'a', text: { es: 'Revisar las facturas una por una y copiar los datos manualmente a una hoja de cálculo', en: 'Review invoices one by one and manually copy data to a spreadsheet', fr: 'Examiner les factures une par une et copier manuellement les données dans un tableur' }, value: 0 }, { id: 'b', text: { es: 'Utilizar las vistas filtradas o el módulo de reportes para generar el informe con los filtros de fecha y estado correspondientes', en: 'Use filtered views or the reports module to generate the report with the appropriate date and status filters', fr: 'Utiliser les vues filtrées ou le module de rapports pour générer le rapport avec les filtres de date et de statut appropriés' }, value: 100 }, { id: 'c', text: { es: 'Pedirle al departamento de TI que genere el reporte', en: 'Ask the IT department to generate the report', fr: 'Demander au département informatique de générer le rapport' }, value: 25 }, { id: 'd', text: { es: 'Exportar toda la base de datos y buscar las facturas manualmente', en: 'Export the entire database and search for invoices manually', fr: 'Exporter toute la base de données et chercher les factures manuellement' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-dyn-prof-4', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-modules', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene trabajando con los diferentes módulos de Microsoft Dynamics 365 (Finanzas, Ventas, Servicio al Cliente, Cadena de Suministro)?', en: 'What level of experience do you have working with the different Microsoft Dynamics 365 modules (Finance, Sales, Customer Service, Supply Chain)?', fr: 'Quel niveau d\'expérience avez-vous avec les différents modules de Microsoft Dynamics 365 (Finance, Ventes, Service Client, Chaîne d\'Approvisionnement) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Sin experiencia en ningún módulo de Dynamics', en: 'No experience with any Dynamics module', fr: 'Aucune expérience avec les modules Dynamics' }, max: { es: 'Dominio avanzado de múltiples módulos y sus interrelaciones', en: 'Advanced proficiency in multiple modules and their interrelations', fr: 'Maîtrise avancée de plusieurs modules et de leurs interrelations' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-dyn-prof-5', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-transactions', type: 'scenario', content: { es: 'Está procesando el cierre mensual en Dynamics 365 y detecta que hay 15 facturas de proveedores que fueron registradas con el tipo de cambio incorrecto durante la última semana. El cierre debe completarse hoy antes de las 5:00 PM. El monto total afectado es significativo y las diferencias impactan los estados financieros.\n\nDescriba paso a paso cómo resolvería esta situación dentro del sistema, qué precauciones tomaría y a quién notificaría.', en: 'You are processing the monthly close in Dynamics 365 and detect that 15 vendor invoices were entered with the incorrect exchange rate during the past week. The close must be completed today before 5:00 PM. The total affected amount is significant and the differences impact the financial statements.\n\nDescribe step by step how you would resolve this situation within the system, what precautions you would take, and who you would notify.', fr: 'Vous traitez la clôture mensuelle dans Dynamics 365 et détectez que 15 factures fournisseurs ont été saisies avec un taux de change incorrect au cours de la dernière semaine. La clôture doit être terminée aujourd\'hui avant 17h00. Le montant total affecté est significatif.\n\nDécrivez étape par étape comment vous résoudriez cette situation dans le système, quelles précautions vous prendriez et qui vous notifieriez.' }, rubric: { es: 'Evaluar: (1) Identificación y documentación de las facturas afectadas, (2) Proceso correcto de reversión o ajuste de tipo de cambio, (3) Notificación al supervisor y al equipo contable, (4) Verificación de los asientos corregidos, (5) Gestión del tiempo para cumplir el plazo, (6) Medidas preventivas propuestas.', en: 'Evaluate: (1) Identification and documentation of affected invoices, (2) Correct exchange rate reversal or adjustment process, (3) Notification to supervisor and accounting team, (4) Verification of corrected entries, (5) Time management to meet deadline, (6) Proposed preventive measures.', fr: 'Évaluer : (1) Identification et documentation des factures affectées, (2) Processus correct de correction du taux de change, (3) Notification au superviseur et à l\'équipe comptable, (4) Vérification des écritures corrigées, (5) Gestion du temps, (6) Mesures préventives proposées.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-dyn-prof-6', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-professional', competencyId: 'ms-dyn-navigation', type: 'open-text', content: { es: 'Describa su flujo de trabajo diario típico en Microsoft Dynamics 365, incluyendo los módulos que utiliza con mayor frecuencia, las transacciones que procesa regularmente y las herramientas o vistas personalizadas que ha configurado para mejorar su productividad.', en: 'Describe your typical daily workflow in Microsoft Dynamics 365, including the modules you use most frequently, the transactions you regularly process, and any custom tools or views you have configured to improve your productivity.', fr: 'Décrivez votre flux de travail quotidien typique dans Microsoft Dynamics 365, y compris les modules que vous utilisez le plus fréquemment, les transactions que vous traitez régulièrement et les outils ou vues personnalisés que vous avez configurés pour améliorer votre productivité.' }, rubric: { es: 'Evaluar: (1) Conocimiento demostrado de los módulos principales, (2) Comprensión de los flujos transaccionales, (3) Uso de vistas personalizadas y filtros, (4) Eficiencia en la navegación del sistema, (5) Capacidad de integrar información entre módulos, (6) Iniciativa para optimizar procesos.', en: 'Evaluate: (1) Demonstrated knowledge of main modules, (2) Understanding of transaction flows, (3) Use of custom views and filters, (4) System navigation efficiency, (5) Ability to integrate information across modules, (6) Initiative to optimize processes.', fr: 'Évaluer : (1) Connaissance démontrée des modules principaux, (2) Compréhension des flux transactionnels, (3) Utilisation de vues personnalisées et filtres, (4) Efficacité de navigation, (5) Intégration d\'information entre modules, (6) Initiative d\'optimisation.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msDynSoftSkillsQuestions: Question[] = [
  { id: 'ms-dyn-ss-1', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-attention-detail', type: 'multiple-choice', content: { es: 'Al ingresar un lote de 50 órdenes de compra en Dynamics 365, nota que los montos de dos órdenes no coinciden con los documentos físicos del proveedor. ¿Qué hace?', en: 'When entering a batch of 50 purchase orders in Dynamics 365, you notice that the amounts of two orders don\'t match the vendor\'s physical documents. What do you do?', fr: 'Lors de la saisie d\'un lot de 50 bons de commande dans Dynamics 365, vous remarquez que les montants de deux commandes ne correspondent pas aux documents physiques du fournisseur. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Detener el ingreso del lote completo, marcar las dos órdenes discrepantes, verificar con el proveedor o el solicitante, y documentar la discrepancia antes de continuar', en: 'Stop entering the full batch, flag the two discrepant orders, verify with the vendor or requester, and document the discrepancy before continuing', fr: 'Arrêter la saisie du lot complet, signaler les deux commandes divergentes, vérifier avec le fournisseur ou le demandeur et documenter l\'écart avant de continuer' }, value: 100 }, { id: 'b', text: { es: 'Ingresar todas las órdenes tal como están y corregir después si alguien lo nota', en: 'Enter all orders as they are and correct later if someone notices', fr: 'Saisir toutes les commandes telles quelles et corriger plus tard si quelqu\'un le remarque' }, value: 0 }, { id: 'c', text: { es: 'Ingresar las 48 órdenes correctas y dejar las 2 pendientes sin documentar', en: 'Enter the 48 correct orders and leave the 2 pending without documentation', fr: 'Saisir les 48 commandes correctes et laisser les 2 en attente sans documentation' }, value: 25 }, { id: 'd', text: { es: 'Ajustar los montos en el sistema para que coincidan con lo que usted cree correcto', en: 'Adjust the amounts in the system to match what you believe is correct', fr: 'Ajuster les montants dans le système pour correspondre à ce que vous pensez être correct' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-dyn-ss-2', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-communication', type: 'multiple-choice', content: { es: 'Un usuario de otro departamento le reporta que un registro en Dynamics 365 muestra información incorrecta, pero usted verifica y los datos son correctos según el proceso establecido. ¿Cómo maneja la situación?', en: 'A user from another department reports that a record in Dynamics 365 shows incorrect information, but you verify and the data is correct per the established process. How do you handle the situation?', fr: 'Un utilisateur d\'un autre département vous signale qu\'un enregistrement dans Dynamics 365 affiche des informations incorrectes, mais vous vérifiez et les données sont correctes selon le processus établi. Comment gérez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Ignorar la queja ya que los datos están correctos', en: 'Ignore the complaint since the data is correct', fr: 'Ignorer la plainte puisque les données sont correctes' }, value: 0 }, { id: 'b', text: { es: 'Explicar al usuario por qué la información es correcta según el proceso, escuchar su perspectiva y ofrecer capacitación si es necesario', en: 'Explain to the user why the information is correct per the process, listen to their perspective, and offer training if needed', fr: 'Expliquer à l\'utilisateur pourquoi l\'information est correcte selon le processus, écouter sa perspective et offrir une formation si nécessaire' }, value: 100 }, { id: 'c', text: { es: 'Cambiar los datos para satisfacer al usuario y evitar conflictos', en: 'Change the data to satisfy the user and avoid conflict', fr: 'Modifier les données pour satisfaire l\'utilisateur et éviter les conflits' }, value: 0 }, { id: 'd', text: { es: 'Remitir al usuario directamente al departamento de TI sin más explicación', en: 'Refer the user directly to the IT department without further explanation', fr: 'Renvoyer l\'utilisateur directement au département informatique sans plus d\'explication' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-dyn-ss-3', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-problem-solving', type: 'multiple-choice', content: { es: 'Dynamics 365 muestra un error que nunca había visto al intentar procesar un pago a proveedor. El pago debe realizarse hoy para evitar cargos por mora. ¿Qué hace?', en: 'Dynamics 365 shows an error you\'ve never seen when trying to process a vendor payment. The payment must be made today to avoid late fees. What do you do?', fr: 'Dynamics 365 affiche une erreur que vous n\'avez jamais vue en essayant de traiter un paiement fournisseur. Le paiement doit être effectué aujourd\'hui pour éviter des pénalités de retard. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Capturar una imagen del error, buscar el código en la documentación de Microsoft, consultar con compañeros experimentados y escalar a soporte técnico si no se resuelve, documentando todo el proceso', en: 'Capture a screenshot of the error, search the code in Microsoft documentation, consult experienced colleagues, and escalate to technical support if unresolved, documenting the entire process', fr: 'Capturer une image de l\'erreur, chercher le code dans la documentation Microsoft, consulter des collègues expérimentés et escalader au support technique si non résolu, en documentant tout le processus' }, value: 100 }, { id: 'b', text: { es: 'Esperar a que el error se resuelva solo e intentar más tarde', en: 'Wait for the error to resolve itself and try again later', fr: 'Attendre que l\'erreur se résolve d\'elle-même et réessayer plus tard' }, value: 0 }, { id: 'c', text: { es: 'Hacer el pago por fuera del sistema y registrarlo después', en: 'Make the payment outside the system and record it later', fr: 'Effectuer le paiement en dehors du système et l\'enregistrer plus tard' }, value: 25 }, { id: 'd', text: { es: 'Cancelar el intento de pago y notificar al proveedor que habrá un retraso', en: 'Cancel the payment attempt and notify the vendor there will be a delay', fr: 'Annuler la tentative de paiement et notifier le fournisseur d\'un retard' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-dyn-ss-4', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-attention-detail', type: 'scale', content: { es: '¿Qué tan riguroso es usted al verificar la exactitud de los datos antes de guardar o confirmar una transacción en el sistema?', en: 'How rigorous are you in verifying data accuracy before saving or confirming a transaction in the system?', fr: 'À quel point êtes-vous rigoureux pour vérifier l\'exactitude des données avant d\'enregistrer ou de confirmer une transaction dans le système ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Generalmente confío en los datos sin verificar', en: 'I generally trust data without verifying', fr: 'Je fais généralement confiance aux données sans vérifier' }, max: { es: 'Siempre verifico cada campo y realizo doble comprobación antes de confirmar', en: 'I always verify every field and double-check before confirming', fr: 'Je vérifie toujours chaque champ et effectue une double vérification avant de confirmer' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-dyn-ss-5', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-communication', type: 'scenario', content: { es: 'El departamento de ventas le reporta que las órdenes de venta que usted procesó la semana pasada tienen descuentos incorrectos que afectan los márgenes de ganancia. Al revisar, descubre que el error fue causado por una actualización reciente de las tablas de precios que nadie le comunicó. El gerente de ventas está molesto y le exige una solución inmediata.\n\nDescriba cómo manejaría esta situación tanto a nivel técnico como interpersonal.', en: 'The sales department reports that the sales orders you processed last week have incorrect discounts affecting profit margins. Upon review, you discover the error was caused by a recent price table update that nobody communicated to you. The sales manager is upset and demands an immediate solution.\n\nDescribe how you would handle this situation both technically and interpersonally.', fr: 'Le département des ventes vous signale que les commandes que vous avez traitées la semaine dernière comportent des remises incorrectes affectant les marges bénéficiaires. En vérifiant, vous découvrez que l\'erreur a été causée par une mise à jour récente des tables de prix qui ne vous a pas été communiquée. Le directeur des ventes est mécontent et exige une solution immédiate.\n\nDécrivez comment vous géreriez cette situation tant sur le plan technique qu\'interpersonnel.' }, rubric: { es: 'Evaluar: (1) Reconocimiento del problema sin evadir responsabilidad, (2) Comunicación empática con el gerente de ventas, (3) Plan técnico para corregir las órdenes afectadas en Dynamics, (4) Propuesta de proceso para evitar que se repita, (5) Escala de prioridades y gestión del tiempo, (6) Actitud profesional ante la presión.', en: 'Evaluate: (1) Problem acknowledgment without evading responsibility, (2) Empathetic communication with sales manager, (3) Technical plan to correct affected orders in Dynamics, (4) Process proposal to prevent recurrence, (5) Priority management and time handling, (6) Professional attitude under pressure.', fr: 'Évaluer : (1) Reconnaissance du problème sans éluder la responsabilité, (2) Communication empathique avec le directeur des ventes, (3) Plan technique pour corriger les commandes, (4) Proposition de processus préventif, (5) Gestion des priorités, (6) Attitude professionnelle sous pression.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-dyn-ss-6', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-soft-skills', competencyId: 'ms-dyn-problem-solving', type: 'open-text', content: { es: 'Describa una situación en la que identificó y resolvió un problema recurrente en el uso de un sistema ERP o de gestión empresarial. ¿Cómo lo detectó, qué pasos siguió para resolverlo y qué resultado obtuvo?', en: 'Describe a situation where you identified and resolved a recurring problem in the use of an ERP or business management system. How did you detect it, what steps did you follow to resolve it, and what was the outcome?', fr: 'Décrivez une situation où vous avez identifié et résolu un problème récurrent dans l\'utilisation d\'un ERP ou d\'un système de gestion. Comment l\'avez-vous détecté, quelles étapes avez-vous suivies pour le résoudre et quel a été le résultat ?' }, rubric: { es: 'Evaluar: (1) Capacidad de observación para detectar patrones problemáticos, (2) Análisis sistemático de la causa raíz, (3) Solución implementada y su efectividad, (4) Comunicación del problema y la solución a los involucrados, (5) Documentación del proceso, (6) Impacto positivo medible.', en: 'Evaluate: (1) Observation skills to detect problematic patterns, (2) Systematic root cause analysis, (3) Implemented solution and its effectiveness, (4) Communication of problem and solution to stakeholders, (5) Process documentation, (6) Measurable positive impact.', fr: 'Évaluer : (1) Capacité d\'observation pour détecter les schémas problématiques, (2) Analyse systématique de la cause racine, (3) Solution mise en œuvre et son efficacité, (4) Communication du problème et de la solution, (5) Documentation du processus, (6) Impact positif mesurable.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msDynReadinessQuestions: Question[] = [
  { id: 'ms-dyn-rd-1', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-platform-updates', type: 'multiple-choice', content: { es: 'Microsoft anuncia una actualización mayor de Dynamics 365 que cambiará significativamente la interfaz del módulo que usted usa diariamente. La actualización se implementará en 4 semanas. ¿Cuál es su reacción?', en: 'Microsoft announces a major Dynamics 365 update that will significantly change the interface of the module you use daily. The update will be deployed in 4 weeks. What is your reaction?', fr: 'Microsoft annonce une mise à jour majeure de Dynamics 365 qui modifiera considérablement l\'interface du module que vous utilisez quotidiennement. La mise à jour sera déployée dans 4 semaines. Quelle est votre réaction ?' }, options: [{ id: 'a', text: { es: 'Revisar proactivamente las notas de la versión, explorar el entorno de pruebas si está disponible y preparar una guía rápida para su equipo sobre los cambios principales', en: 'Proactively review the release notes, explore the test environment if available, and prepare a quick guide for your team on the main changes', fr: 'Examiner proactivement les notes de version, explorer l\'environnement de test s\'il est disponible et préparer un guide rapide pour votre équipe sur les principaux changements' }, value: 100 }, { id: 'b', text: { es: 'Esperar a que se implemente la actualización y aprender sobre la marcha', en: 'Wait for the update to be deployed and learn on the go', fr: 'Attendre le déploiement de la mise à jour et apprendre au fur et à mesure' }, value: 25 }, { id: 'c', text: { es: 'Quejarse con el supervisor y solicitar que pospongan la actualización', en: 'Complain to your supervisor and request that the update be postponed', fr: 'Se plaindre au superviseur et demander le report de la mise à jour' }, value: 0 }, { id: 'd', text: { es: 'Ignorar el anuncio ya que las actualizaciones generalmente no afectan mucho', en: 'Ignore the announcement since updates generally don\'t affect things much', fr: 'Ignorer l\'annonce car les mises à jour n\'affectent généralement pas beaucoup les choses' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-dyn-rd-2', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-process-improvement', type: 'multiple-choice', content: { es: 'Nota que un proceso que realiza diariamente en Dynamics 365 requiere 12 pasos manuales y consume 45 minutos. Cree que podría simplificarse. ¿Qué hace?', en: 'You notice that a process you perform daily in Dynamics 365 requires 12 manual steps and takes 45 minutes. You believe it could be simplified. What do you do?', fr: 'Vous remarquez qu\'un processus que vous effectuez quotidiennement dans Dynamics 365 nécessite 12 étapes manuelles et prend 45 minutes. Vous pensez qu\'il pourrait être simplifié. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Documentar el proceso actual, identificar los pasos que podrían automatizarse o eliminarse, y presentar una propuesta de mejora al supervisor con los beneficios estimados', en: 'Document the current process, identify steps that could be automated or eliminated, and present an improvement proposal to your supervisor with estimated benefits', fr: 'Documenter le processus actuel, identifier les étapes qui pourraient être automatisées ou éliminées, et présenter une proposition d\'amélioration au superviseur avec les bénéfices estimés' }, value: 100 }, { id: 'b', text: { es: 'Seguir realizando el proceso tal como está ya que siempre se ha hecho así', en: 'Continue performing the process as is since it has always been done this way', fr: 'Continuer à effectuer le processus tel quel puisqu\'il a toujours été fait ainsi' }, value: 0 }, { id: 'c', text: { es: 'Cambiar el proceso por su cuenta sin consultar a nadie', en: 'Change the process on your own without consulting anyone', fr: 'Modifier le processus de votre propre initiative sans consulter personne' }, value: 25 }, { id: 'd', text: { es: 'Mencionarlo casualmente en una reunión pero sin preparar una propuesta formal', en: 'Mention it casually in a meeting but without preparing a formal proposal', fr: 'Le mentionner en passant lors d\'une réunion mais sans préparer de proposition formelle' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-dyn-rd-3', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-digital-literacy', type: 'multiple-choice', content: { es: 'Su empresa está integrando Power Automate con Dynamics 365 para automatizar aprobaciones de órdenes de compra. Le piden aprender a crear flujos básicos. ¿Cómo responde?', en: 'Your company is integrating Power Automate with Dynamics 365 to automate purchase order approvals. You are asked to learn how to create basic flows. How do you respond?', fr: 'Votre entreprise intègre Power Automate avec Dynamics 365 pour automatiser les approbations de bons de commande. On vous demande d\'apprendre à créer des flux de base. Comment répondez-vous ?' }, options: [{ id: 'a', text: { es: 'Aceptar con entusiasmo, inscribirse en los cursos gratuitos de Microsoft Learn, practicar con plantillas existentes y compartir lo aprendido con el equipo', en: 'Accept enthusiastically, enroll in free Microsoft Learn courses, practice with existing templates, and share what you learn with the team', fr: 'Accepter avec enthousiasme, s\'inscrire aux cours gratuits de Microsoft Learn, pratiquer avec des modèles existants et partager les connaissances avec l\'équipe' }, value: 100 }, { id: 'b', text: { es: 'Indicar que eso es trabajo del departamento de TI y no le corresponde', en: 'Indicate that this is IT department work and not your responsibility', fr: 'Indiquer que c\'est le travail du département informatique et que ce n\'est pas votre responsabilité' }, value: 0 }, { id: 'c', text: { es: 'Aceptar pero sin hacer esfuerzo real por aprender la herramienta', en: 'Accept but make no real effort to learn the tool', fr: 'Accepter mais ne faire aucun effort réel pour apprendre l\'outil' }, value: 0 }, { id: 'd', text: { es: 'Aceptar y esperar a que le den una capacitación formal antes de intentar cualquier cosa', en: 'Accept and wait for formal training before attempting anything', fr: 'Accepter et attendre une formation formelle avant de tenter quoi que ce soit' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-dyn-rd-4', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-platform-updates', type: 'scale', content: { es: '¿Qué tan cómodo se siente adaptándose a nuevas versiones, actualizaciones o cambios en las herramientas tecnológicas que utiliza en su trabajo?', en: 'How comfortable do you feel adapting to new versions, updates, or changes in the technology tools you use at work?', fr: 'À quel point vous sentez-vous à l\'aise pour vous adapter aux nouvelles versions, mises à jour ou changements des outils technologiques que vous utilisez au travail ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Los cambios tecnológicos me generan mucha ansiedad y resistencia', en: 'Technology changes cause me a lot of anxiety and resistance', fr: 'Les changements technologiques me causent beaucoup d\'anxiété et de résistance' }, max: { es: 'Disfruto explorar nuevas funcionalidades y me adapto rápidamente', en: 'I enjoy exploring new features and adapt quickly', fr: 'J\'aime explorer les nouvelles fonctionnalités et je m\'adapte rapidement' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-dyn-rd-5', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-process-improvement', type: 'scenario', content: { es: 'Su empresa decide migrar de la versión on-premise de Dynamics a Dynamics 365 en la nube. Usted lleva 5 años trabajando con la versión anterior y conoce todos sus atajos y personalizaciones. En la nueva versión, muchos de los procesos que dominaba funcionan de manera diferente y las personalizaciones anteriores no se migrarán automáticamente.\n\nDescriba cómo abordaría esta transición para mantener su productividad y ayudar a su equipo en el proceso.', en: 'Your company decides to migrate from the on-premise version of Dynamics to cloud-based Dynamics 365. You have been working with the previous version for 5 years and know all its shortcuts and customizations. In the new version, many processes you mastered work differently and previous customizations will not be automatically migrated.\n\nDescribe how you would approach this transition to maintain your productivity and help your team through the process.', fr: 'Votre entreprise décide de migrer de la version on-premise de Dynamics vers Dynamics 365 dans le cloud. Vous travaillez avec la version précédente depuis 5 ans et connaissez tous ses raccourcis et personnalisations. Dans la nouvelle version, de nombreux processus que vous maîtrisiez fonctionnent différemment et les personnalisations précédentes ne seront pas migrées automatiquement.\n\nDécrivez comment vous aborderiez cette transition pour maintenir votre productivité et aider votre équipe.' }, rubric: { es: 'Evaluar: (1) Actitud positiva y proactiva ante el cambio, (2) Plan de aprendizaje estructurado, (3) Documentación de procesos actuales vs. nuevos, (4) Disposición para ayudar a compañeros, (5) Identificación de funcionalidades equivalentes o mejoradas, (6) Gestión de expectativas y tiempos de adaptación.', en: 'Evaluate: (1) Positive and proactive attitude toward change, (2) Structured learning plan, (3) Documentation of current vs. new processes, (4) Willingness to help colleagues, (5) Identification of equivalent or improved features, (6) Managing expectations and adaptation timelines.', fr: 'Évaluer : (1) Attitude positive et proactive face au changement, (2) Plan d\'apprentissage structuré, (3) Documentation des processus actuels vs. nouveaux, (4) Disposition à aider les collègues, (5) Identification des fonctionnalités équivalentes, (6) Gestion des attentes et délais d\'adaptation.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-dyn-rd-6', profileId: 'ms-dynamics-operator', categoryId: 'ms-dyn-readiness', competencyId: 'ms-dyn-digital-literacy', type: 'open-text', content: { es: 'Describa qué herramientas digitales complementarias a Dynamics 365 conoce o utiliza (por ejemplo, Power BI, Power Automate, Excel avanzado, Teams) y cómo las integra en su trabajo diario para mejorar la eficiencia de sus procesos.', en: 'Describe what complementary digital tools to Dynamics 365 you know or use (for example, Power BI, Power Automate, advanced Excel, Teams) and how you integrate them into your daily work to improve process efficiency.', fr: 'Décrivez quels outils numériques complémentaires à Dynamics 365 vous connaissez ou utilisez (par exemple, Power BI, Power Automate, Excel avancé, Teams) et comment vous les intégrez dans votre travail quotidien pour améliorer l\'efficacité de vos processus.' }, rubric: { es: 'Evaluar: (1) Amplitud de herramientas digitales conocidas, (2) Nivel de integración práctica con Dynamics, (3) Ejemplos concretos de uso, (4) Comprensión del ecosistema Microsoft, (5) Iniciativa de aprendizaje continuo, (6) Impacto en productividad demostrado.', en: 'Evaluate: (1) Breadth of digital tools known, (2) Level of practical integration with Dynamics, (3) Concrete usage examples, (4) Understanding of Microsoft ecosystem, (5) Continuous learning initiative, (6) Demonstrated productivity impact.', fr: 'Évaluer : (1) Étendue des outils numériques connus, (2) Niveau d\'intégration pratique avec Dynamics, (3) Exemples concrets d\'utilisation, (4) Compréhension de l\'écosystème Microsoft, (5) Initiative d\'apprentissage continu, (6) Impact démontré sur la productivité.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

