// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msOfficeProfessionalQuestions: Question[] = [
  { id: 'ms-office-prof-1', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-word', type: 'multiple-choice', content: { es: 'Debe crear un informe de 30 páginas en Word con tabla de contenido, encabezados numerados, referencias cruzadas y bibliografía. ¿Cuál es el enfoque más profesional?', en: 'You need to create a 30-page report in Word with a table of contents, numbered headings, cross-references, and bibliography. What is the most professional approach?', fr: 'Vous devez créer un rapport de 30 pages dans Word avec une table des matières, des titres numérotés, des renvois et une bibliographie. Quelle est l\'approche la plus professionnelle ?' }, options: [{ id: 'a', text: { es: 'Usar estilos de título integrados (Heading 1, 2, 3), insertar tabla de contenido automática, utilizar referencias cruzadas vinculadas y gestionar fuentes con el administrador de bibliografía de Word', en: 'Use built-in heading styles (Heading 1, 2, 3), insert an automatic table of contents, use linked cross-references, and manage sources with Word\'s bibliography manager', fr: 'Utiliser les styles de titre intégrés (Titre 1, 2, 3), insérer une table des matières automatique, utiliser des renvois liés et gérer les sources avec le gestionnaire de bibliographie de Word' }, value: 100 }, { id: 'b', text: { es: 'Formatear manualmente cada título con negrita y tamaño grande, escribir la tabla de contenido a mano', en: 'Manually format each title with bold and large size, write the table of contents by hand', fr: 'Formater manuellement chaque titre en gras et grande taille, écrire la table des matières à la main' }, value: 0 }, { id: 'c', text: { es: 'Usar estilos de título pero crear la tabla de contenido manualmente para tener más control', en: 'Use heading styles but create the table of contents manually for more control', fr: 'Utiliser les styles de titre mais créer la table des matières manuellement pour plus de contrôle' }, value: 25 }, { id: 'd', text: { es: 'Crear el documento sin estructura formal y agregar formato al final', en: 'Create the document without formal structure and add formatting at the end', fr: 'Créer le document sans structure formelle et ajouter le formatage à la fin' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-office-prof-2', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-excel', type: 'multiple-choice', content: { es: 'Necesita analizar una base de datos de 5,000 registros de ventas en Excel para identificar los productos más rentables por región y trimestre. ¿Qué herramientas de Excel utilizaría?', en: 'You need to analyze a database of 5,000 sales records in Excel to identify the most profitable products by region and quarter. What Excel tools would you use?', fr: 'Vous devez analyser une base de données de 5 000 enregistrements de ventes dans Excel pour identifier les produits les plus rentables par région et par trimestre. Quels outils Excel utiliseriez-vous ?' }, options: [{ id: 'a', text: { es: 'Ordenar los datos manualmente y usar la calculadora para sumar las ventas', en: 'Sort data manually and use a calculator to add up sales', fr: 'Trier les données manuellement et utiliser une calculatrice pour additionner les ventes' }, value: 0 }, { id: 'b', text: { es: 'Crear una tabla dinámica (PivotTable) con campos de producto, región y trimestre, aplicar filtros y segmentaciones, y complementar con gráficos dinámicos para visualizar tendencias', en: 'Create a PivotTable with product, region, and quarter fields, apply filters and slicers, and complement with PivotCharts to visualize trends', fr: 'Créer un tableau croisé dynamique avec les champs produit, région et trimestre, appliquer des filtres et des segments, et compléter avec des graphiques croisés dynamiques pour visualiser les tendances' }, value: 100 }, { id: 'c', text: { es: 'Usar únicamente BUSCARV (VLOOKUP) para buscar productos uno por uno', en: 'Use only VLOOKUP to search for products one by one', fr: 'Utiliser uniquement RECHERCHEV pour chercher les produits un par un' }, value: 25 }, { id: 'd', text: { es: 'Copiar los datos a un documento de Word y crear tablas manualmente', en: 'Copy the data to a Word document and create tables manually', fr: 'Copier les données dans un document Word et créer des tableaux manuellement' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-office-prof-3', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-powerpoint', type: 'multiple-choice', content: { es: 'Debe preparar una presentación ejecutiva en PowerPoint para la junta directiva. Tiene 20 minutos para presentar resultados trimestrales complejos. ¿Cuál es la mejor estrategia de diseño?', en: 'You need to prepare an executive PowerPoint presentation for the board of directors. You have 20 minutes to present complex quarterly results. What is the best design strategy?', fr: 'Vous devez préparer une présentation PowerPoint exécutive pour le conseil d\'administration. Vous avez 20 minutes pour présenter des résultats trimestriels complexes. Quelle est la meilleure stratégie de conception ?' }, options: [{ id: 'a', text: { es: 'Incluir toda la información disponible en cada diapositiva para no omitir nada', en: 'Include all available information on each slide to not miss anything', fr: 'Inclure toutes les informations disponibles sur chaque diapositive pour ne rien omettre' }, value: 0 }, { id: 'b', text: { es: 'Usar una plantilla corporativa consistente, limitar a un mensaje clave por diapositiva, utilizar gráficos claros con datos relevantes, incluir notas del orador para detalles y agregar un apéndice con datos de respaldo', en: 'Use a consistent corporate template, limit to one key message per slide, use clear charts with relevant data, include speaker notes for details, and add an appendix with supporting data', fr: 'Utiliser un modèle corporatif cohérent, limiter à un message clé par diapositive, utiliser des graphiques clairs avec des données pertinentes, inclure des notes pour les détails et ajouter une annexe avec des données de support' }, value: 100 }, { id: 'c', text: { es: 'Copiar las tablas directamente de Excel sin formato adicional', en: 'Copy tables directly from Excel without additional formatting', fr: 'Copier les tableaux directement depuis Excel sans formatage supplémentaire' }, value: 25 }, { id: 'd', text: { es: 'Usar muchas animaciones y transiciones para hacer la presentación más dinámica', en: 'Use many animations and transitions to make the presentation more dynamic', fr: 'Utiliser beaucoup d\'animations et de transitions pour rendre la présentation plus dynamique' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-office-prof-4', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-productivity', type: 'scale', content: { es: '¿Qué nivel de dominio tiene en el uso integrado de las aplicaciones de Microsoft Office/365 (Word, Excel, PowerPoint, Outlook, OneDrive)?', en: 'What level of proficiency do you have in the integrated use of Microsoft Office/365 applications (Word, Excel, PowerPoint, Outlook, OneDrive)?', fr: 'Quel niveau de maîtrise avez-vous dans l\'utilisation intégrée des applications Microsoft Office/365 (Word, Excel, PowerPoint, Outlook, OneDrive) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Uso básico limitado a funciones elementales', en: 'Basic usage limited to elementary functions', fr: 'Utilisation basique limitée aux fonctions élémentaires' }, max: { es: 'Dominio avanzado con uso de macros, automatización y funciones especializadas', en: 'Advanced proficiency with macros, automation, and specialized functions', fr: 'Maîtrise avancée avec macros, automatisation et fonctions spécialisées' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-office-prof-5', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-excel', type: 'scenario', content: { es: 'Su jefe le pide crear un dashboard en Excel que consolide datos de ventas de 5 sucursales, cada una con su propio archivo Excel con formatos diferentes. Los datos deben actualizarse semanalmente, mostrar KPIs comparativos y permitir filtrar por sucursal, producto y período. El dashboard será revisado por el director general cada lunes.\n\nDescriba paso a paso cómo diseñaría y construiría este dashboard, incluyendo la estructura de datos, fórmulas clave y consideraciones de actualización.', en: 'Your boss asks you to create an Excel dashboard that consolidates sales data from 5 branches, each with its own Excel file in different formats. The data must be updated weekly, show comparative KPIs, and allow filtering by branch, product, and period. The dashboard will be reviewed by the CEO every Monday.\n\nDescribe step by step how you would design and build this dashboard, including data structure, key formulas, and update considerations.', fr: 'Votre chef vous demande de créer un tableau de bord Excel qui consolide les données de ventes de 5 succursales, chacune avec son propre fichier Excel dans des formats différents. Les données doivent être mises à jour chaque semaine, montrer des KPI comparatifs et permettre le filtrage par succursale, produit et période.\n\nDécrivez étape par étape comment vous concevriez et construiriez ce tableau de bord.' }, rubric: { es: 'Evaluar: (1) Estandarización de formatos de datos de origen, (2) Uso de Power Query o conexiones de datos para consolidación, (3) Estructura de tabla dinámica y modelo de datos, (4) Fórmulas y funciones apropiadas (SUMIFS, INDEX-MATCH, etc.), (5) Diseño visual con gráficos y segmentaciones, (6) Plan de actualización y mantenimiento.', en: 'Evaluate: (1) Standardization of source data formats, (2) Use of Power Query or data connections for consolidation, (3) PivotTable structure and data model, (4) Appropriate formulas and functions (SUMIFS, INDEX-MATCH, etc.), (5) Visual design with charts and slicers, (6) Update and maintenance plan.', fr: 'Évaluer : (1) Standardisation des formats de données sources, (2) Utilisation de Power Query ou connexions de données, (3) Structure de tableau croisé dynamique, (4) Formules et fonctions appropriées, (5) Conception visuelle avec graphiques, (6) Plan de mise à jour et maintenance.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-office-prof-6', profileId: 'ms-office-user', categoryId: 'ms-office-professional', competencyId: 'ms-office-word', type: 'open-text', content: { es: 'Describa las funcionalidades avanzadas de Microsoft Word que utiliza regularmente en su trabajo (por ejemplo, combinación de correspondencia, macros, control de cambios, plantillas, formularios). Incluya ejemplos concretos de cómo estas funcionalidades le han ayudado a mejorar la calidad y eficiencia de sus documentos.', en: 'Describe the advanced Microsoft Word features you regularly use in your work (for example, mail merge, macros, track changes, templates, forms). Include concrete examples of how these features have helped you improve document quality and efficiency.', fr: 'Décrivez les fonctionnalités avancées de Microsoft Word que vous utilisez régulièrement dans votre travail (par exemple, publipostage, macros, suivi des modifications, modèles, formulaires). Incluez des exemples concrets de comment ces fonctionnalités vous ont aidé à améliorer la qualité et l\'efficacité de vos documents.' }, rubric: { es: 'Evaluar: (1) Variedad de funcionalidades avanzadas conocidas, (2) Profundidad de uso demostrada, (3) Ejemplos prácticos y relevantes, (4) Impacto en productividad, (5) Capacidad de crear documentos profesionales complejos, (6) Uso de automatización y plantillas.', en: 'Evaluate: (1) Variety of advanced features known, (2) Demonstrated depth of use, (3) Practical and relevant examples, (4) Productivity impact, (5) Ability to create complex professional documents, (6) Use of automation and templates.', fr: 'Évaluer : (1) Variété des fonctionnalités avancées connues, (2) Profondeur d\'utilisation démontrée, (3) Exemples pratiques et pertinents, (4) Impact sur la productivité, (5) Capacité à créer des documents professionnels complexes, (6) Utilisation de l\'automatisation et des modèles.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msOfficeSoftSkillsQuestions: Question[] = [
  { id: 'ms-office-ss-1', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-written-comm', type: 'multiple-choice', content: { es: 'Debe enviar un correo electrónico en Outlook a toda la empresa comunicando un cambio importante en la política de vacaciones. ¿Cuál es el enfoque más efectivo?', en: 'You need to send an Outlook email to the entire company communicating an important change in vacation policy. What is the most effective approach?', fr: 'Vous devez envoyer un courriel dans Outlook à toute l\'entreprise pour communiquer un changement important dans la politique de vacances. Quelle est l\'approche la plus efficace ?' }, options: [{ id: 'a', text: { es: 'Escribir un correo largo y detallado con toda la información técnica y legal del cambio', en: 'Write a long, detailed email with all technical and legal information about the change', fr: 'Écrire un courriel long et détaillé avec toutes les informations techniques et juridiques du changement' }, value: 25 }, { id: 'b', text: { es: 'Redactar un mensaje claro y conciso con el cambio principal en el asunto, resumen ejecutivo al inicio, puntos clave en viñetas, fecha de vigencia destacada y enlace al documento completo para quien necesite más detalle', en: 'Draft a clear, concise message with the main change in the subject line, executive summary at the top, key points in bullets, highlighted effective date, and link to the full document for those who need more detail', fr: 'Rédiger un message clair et concis avec le changement principal dans l\'objet, un résumé exécutif au début, les points clés en puces, la date d\'entrée en vigueur mise en évidence et un lien vers le document complet pour ceux qui ont besoin de plus de détails' }, value: 100 }, { id: 'c', text: { es: 'Enviar solo el documento de política adjunto sin explicación en el cuerpo del correo', en: 'Send only the attached policy document without explanation in the email body', fr: 'Envoyer uniquement le document de politique en pièce jointe sans explication dans le corps du courriel' }, value: 0 }, { id: 'd', text: { es: 'Publicar la información en un chat de Teams sin enviar correo formal', en: 'Post the information in a Teams chat without sending a formal email', fr: 'Publier l\'information dans un chat Teams sans envoyer de courriel formel' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-office-ss-2', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-organization', type: 'multiple-choice', content: { es: 'Recibe más de 100 correos diarios en Outlook y frecuentemente pierde mensajes importantes entre la cantidad. ¿Cómo mejoraría su gestión de correo?', en: 'You receive over 100 daily emails in Outlook and frequently miss important messages among the volume. How would you improve your email management?', fr: 'Vous recevez plus de 100 courriels par jour dans Outlook et manquez fréquemment des messages importants. Comment amélioreriez-vous votre gestion des courriels ?' }, options: [{ id: 'a', text: { es: 'Crear reglas automáticas para categorizar correos por remitente/proyecto, usar carpetas organizadas, configurar alertas para remitentes prioritarios y establecer horarios fijos para revisar correo no urgente', en: 'Create automatic rules to categorize emails by sender/project, use organized folders, set alerts for priority senders, and establish fixed schedules for reviewing non-urgent mail', fr: 'Créer des règles automatiques pour catégoriser les courriels par expéditeur/projet, utiliser des dossiers organisés, configurer des alertes pour les expéditeurs prioritaires et établir des horaires fixes pour le courrier non urgent' }, value: 100 }, { id: 'b', text: { es: 'Leer todos los correos en el orden en que llegan, del primero al último', en: 'Read all emails in the order they arrive, from first to last', fr: 'Lire tous les courriels dans l\'ordre d\'arrivée, du premier au dernier' }, value: 0 }, { id: 'c', text: { es: 'Marcar todos como leídos y responder solo a los que le reenvían', en: 'Mark all as read and only respond to those that are forwarded to you again', fr: 'Tout marquer comme lu et ne répondre qu\'aux courriels qui vous sont renvoyés' }, value: 0 }, { id: 'd', text: { es: 'Crear una sola carpeta donde mueve los correos importantes manualmente', en: 'Create a single folder where you manually move important emails', fr: 'Créer un seul dossier où vous déplacez manuellement les courriels importants' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-office-ss-3', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-collaboration', type: 'multiple-choice', content: { es: 'Tres compañeros y usted deben colaborar en un documento Word que requiere aprobación del gerente para el viernes. Cada uno debe agregar una sección diferente. ¿Cómo organiza el trabajo colaborativo?', en: 'Three colleagues and you need to collaborate on a Word document that requires manager approval by Friday. Each person must add a different section. How do you organize the collaborative work?', fr: 'Trois collègues et vous devez collaborer sur un document Word qui nécessite l\'approbation du responsable pour vendredi. Chacun doit ajouter une section différente. Comment organisez-vous le travail collaboratif ?' }, options: [{ id: 'a', text: { es: 'Crear el documento en OneDrive/SharePoint, compartirlo con permisos de edición, asignar secciones claras a cada persona, usar la coautoría en tiempo real y el control de cambios para revisiones', en: 'Create the document in OneDrive/SharePoint, share with editing permissions, assign clear sections to each person, use real-time co-authoring and track changes for reviews', fr: 'Créer le document dans OneDrive/SharePoint, partager avec des permissions d\'édition, assigner des sections claires à chaque personne, utiliser la co-édition en temps réel et le suivi des modifications pour les révisions' }, value: 100 }, { id: 'b', text: { es: 'Cada persona crea su sección en un archivo separado y usted los fusiona al final', en: 'Each person creates their section in a separate file and you merge them at the end', fr: 'Chaque personne crée sa section dans un fichier séparé et vous les fusionnez à la fin' }, value: 25 }, { id: 'c', text: { es: 'Enviar el documento por correo a cada persona para que trabaje por turnos', en: 'Email the document to each person to work in turns', fr: 'Envoyer le document par courriel à chaque personne pour travailler à tour de rôle' }, value: 25 }, { id: 'd', text: { es: 'Escribir todo usted mismo para asegurar consistencia y pedirles solo que revisen', en: 'Write everything yourself to ensure consistency and only ask them to review', fr: 'Tout écrire vous-même pour assurer la cohérence et leur demander seulement de réviser' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-office-ss-4', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-written-comm', type: 'scale', content: { es: '¿Qué tan efectiva considera su comunicación escrita en correos electrónicos, informes y documentos profesionales?', en: 'How effective do you consider your written communication in emails, reports, and professional documents?', fr: 'À quel point considérez-vous votre communication écrite efficace dans les courriels, rapports et documents professionnels ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Mis documentos frecuentemente requieren correcciones significativas de otros', en: 'My documents frequently require significant corrections from others', fr: 'Mes documents nécessitent fréquemment des corrections significatives de la part d\'autres personnes' }, max: { es: 'Mis documentos son consistentemente claros, bien estructurados y raramente requieren revisión', en: 'My documents are consistently clear, well-structured, and rarely require revision', fr: 'Mes documents sont systématiquement clairs, bien structurés et nécessitent rarement des révisions' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-office-ss-5', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-collaboration', type: 'scenario', content: { es: 'Usted es el responsable de coordinar la creación del informe anual de la empresa. Participan 8 departamentos, cada uno debe entregar su sección en Word con datos de soporte en Excel. Tiene 3 semanas para consolidar todo en un documento final profesional con formato uniforme, gráficos integrados y versión PDF para distribución. Dos departamentos tienen historial de entregar tarde.\n\nDescriba su plan completo de coordinación, herramientas que utilizaría y cómo manejaría los riesgos de entrega tardía.', en: 'You are responsible for coordinating the creation of the company\'s annual report. Eight departments participate, each must deliver their section in Word with supporting data in Excel. You have 3 weeks to consolidate everything into a professional final document with uniform formatting, integrated charts, and a PDF version for distribution. Two departments have a history of late delivery.\n\nDescribe your complete coordination plan, tools you would use, and how you would manage late delivery risks.', fr: 'Vous êtes responsable de la coordination de la création du rapport annuel de l\'entreprise. Huit départements participent, chacun doit livrer sa section en Word avec des données de support en Excel. Vous avez 3 semaines pour consolider le tout en un document final professionnel avec un format uniforme, des graphiques intégrés et une version PDF.\n\nDécrivez votre plan complet de coordination, les outils que vous utiliseriez et comment vous géreriez les risques de livraison tardive.' }, rubric: { es: 'Evaluar: (1) Plan de trabajo con cronograma y hitos, (2) Uso de herramientas colaborativas (SharePoint, Teams, OneDrive), (3) Plantilla estandarizada proporcionada a los departamentos, (4) Estrategia proactiva para departamentos con historial de retraso, (5) Proceso de revisión y control de calidad, (6) Plan de contingencia y gestión de versiones.', en: 'Evaluate: (1) Work plan with timeline and milestones, (2) Use of collaborative tools (SharePoint, Teams, OneDrive), (3) Standardized template provided to departments, (4) Proactive strategy for departments with late delivery history, (5) Review and quality control process, (6) Contingency plan and version management.', fr: 'Évaluer : (1) Plan de travail avec chronogramme et jalons, (2) Utilisation d\'outils collaboratifs, (3) Modèle standardisé fourni aux départements, (4) Stratégie proactive pour les départements en retard, (5) Processus de révision et contrôle qualité, (6) Plan de contingence et gestion des versions.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-office-ss-6', profileId: 'ms-office-user', categoryId: 'ms-office-soft-skills', competencyId: 'ms-office-organization', type: 'open-text', content: { es: 'Describa su sistema personal de organización digital: cómo estructura sus archivos en OneDrive o su computadora, cómo gestiona su calendario en Outlook, cómo prioriza tareas y cómo asegura que no se pierda información importante. Incluya herramientas o métodos específicos que utiliza.', en: 'Describe your personal digital organization system: how you structure your files in OneDrive or your computer, how you manage your Outlook calendar, how you prioritize tasks, and how you ensure important information is not lost. Include specific tools or methods you use.', fr: 'Décrivez votre système personnel d\'organisation numérique : comment vous structurez vos fichiers dans OneDrive ou votre ordinateur, comment vous gérez votre calendrier Outlook, comment vous priorisez les tâches et comment vous vous assurez de ne pas perdre d\'informations importantes.' }, rubric: { es: 'Evaluar: (1) Estructura lógica y consistente de archivos, (2) Uso efectivo del calendario y recordatorios, (3) Sistema de priorización de tareas, (4) Uso de herramientas de productividad (To Do, Planner, etc.), (5) Estrategia de respaldo de información, (6) Disciplina y consistencia en la organización.', en: 'Evaluate: (1) Logical and consistent file structure, (2) Effective calendar and reminder use, (3) Task prioritization system, (4) Use of productivity tools (To Do, Planner, etc.), (5) Information backup strategy, (6) Discipline and consistency in organization.', fr: 'Évaluer : (1) Structure logique et cohérente des fichiers, (2) Utilisation efficace du calendrier et des rappels, (3) Système de priorisation des tâches, (4) Utilisation d\'outils de productivité, (5) Stratégie de sauvegarde, (6) Discipline et cohérence dans l\'organisation.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msOfficeReadinessQuestions: Question[] = [
  { id: 'ms-office-rd-1', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-cloud-tools', type: 'multiple-choice', content: { es: 'Su empresa está migrando de Office instalado localmente a Microsoft 365 en la nube. Algunos compañeros están preocupados por perder sus archivos locales. ¿Cómo abordaría la transición?', en: 'Your company is migrating from locally installed Office to cloud-based Microsoft 365. Some colleagues are worried about losing their local files. How would you approach the transition?', fr: 'Votre entreprise migre d\'Office installé localement vers Microsoft 365 dans le cloud. Certains collègues s\'inquiètent de perdre leurs fichiers locaux. Comment aborderiez-vous la transition ?' }, options: [{ id: 'a', text: { es: 'Aprender las ventajas del trabajo en la nube, ayudar a compañeros a migrar sus archivos a OneDrive con sincronización, y demostrar los beneficios de la colaboración en tiempo real y el acceso desde cualquier dispositivo', en: 'Learn the advantages of cloud work, help colleagues migrate their files to OneDrive with sync, and demonstrate the benefits of real-time collaboration and access from any device', fr: 'Apprendre les avantages du travail dans le cloud, aider les collègues à migrer leurs fichiers vers OneDrive avec synchronisation, et démontrer les avantages de la collaboration en temps réel et de l\'accès depuis n\'importe quel appareil' }, value: 100 }, { id: 'b', text: { es: 'Resistirse al cambio y seguir guardando todo localmente', en: 'Resist the change and continue saving everything locally', fr: 'Résister au changement et continuer à tout enregistrer localement' }, value: 0 }, { id: 'c', text: { es: 'Aceptar el cambio pasivamente pero sin explorar las nuevas funcionalidades', en: 'Accept the change passively but without exploring new features', fr: 'Accepter le changement passivement mais sans explorer les nouvelles fonctionnalités' }, value: 25 }, { id: 'd', text: { es: 'Guardar copias de todo en USB como respaldo por si la nube falla', en: 'Save copies of everything on USB as backup in case the cloud fails', fr: 'Sauvegarder des copies de tout sur USB comme sauvegarde au cas où le cloud échouerait' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-office-rd-2', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-ai-copilot', type: 'multiple-choice', content: { es: 'Microsoft introduce Copilot AI en las aplicaciones de Office 365. Le ofrecen acceso temprano para probarlo en su trabajo diario. ¿Cuál es su reacción?', en: 'Microsoft introduces Copilot AI in Office 365 applications. You are offered early access to try it in your daily work. What is your reaction?', fr: 'Microsoft introduit Copilot AI dans les applications Office 365. On vous offre un accès anticipé pour l\'essayer dans votre travail quotidien. Quelle est votre réaction ?' }, options: [{ id: 'a', text: { es: 'Rechazar porque la IA podría cometer errores o reemplazar su trabajo', en: 'Decline because AI could make mistakes or replace your job', fr: 'Refuser parce que l\'IA pourrait commettre des erreurs ou remplacer votre travail' }, value: 0 }, { id: 'b', text: { es: 'Aceptar con entusiasmo, explorar las capacidades de Copilot en Word, Excel y PowerPoint, identificar tareas donde agiliza el trabajo, verificar siempre los resultados generados y compartir mejores prácticas con el equipo', en: 'Accept enthusiastically, explore Copilot capabilities in Word, Excel, and PowerPoint, identify tasks where it speeds up work, always verify generated results, and share best practices with the team', fr: 'Accepter avec enthousiasme, explorer les capacités de Copilot dans Word, Excel et PowerPoint, identifier les tâches où il accélère le travail, toujours vérifier les résultats générés et partager les meilleures pratiques avec l\'équipe' }, value: 100 }, { id: 'c', text: { es: 'Aceptar pero usarlo solo para tareas triviales sin explorar su potencial completo', en: 'Accept but use it only for trivial tasks without exploring its full potential', fr: 'Accepter mais l\'utiliser uniquement pour des tâches triviales sans explorer son plein potentiel' }, value: 25 }, { id: 'd', text: { es: 'Esperar a que otros lo prueben primero y luego decidir', en: 'Wait for others to try it first and then decide', fr: 'Attendre que d\'autres l\'essaient d\'abord puis décider' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-office-rd-3', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-workflow-optimization', type: 'multiple-choice', content: { es: 'Descubre que varios procesos administrativos repetitivos en su área (como generar reportes semanales, enviar recordatorios y consolidar datos) podrían automatizarse con Power Automate. ¿Qué hace?', en: 'You discover that several repetitive administrative processes in your area (like generating weekly reports, sending reminders, and consolidating data) could be automated with Power Automate. What do you do?', fr: 'Vous découvrez que plusieurs processus administratifs répétitifs dans votre service (comme générer des rapports hebdomadaires, envoyer des rappels et consolider des données) pourraient être automatisés avec Power Automate. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Investigar Power Automate, crear flujos piloto para los procesos más simples, medir el ahorro de tiempo, presentar los resultados al jefe y proponer un plan de automatización gradual', en: 'Research Power Automate, create pilot flows for the simplest processes, measure time savings, present results to your boss, and propose a gradual automation plan', fr: 'Rechercher Power Automate, créer des flux pilotes pour les processus les plus simples, mesurer le gain de temps, présenter les résultats au chef et proposer un plan d\'automatisation progressif' }, value: 100 }, { id: 'b', text: { es: 'Seguir haciendo los procesos manualmente ya que siempre han funcionado así', en: 'Continue doing processes manually since they have always worked that way', fr: 'Continuer à faire les processus manuellement puisqu\'ils ont toujours fonctionné ainsi' }, value: 0 }, { id: 'c', text: { es: 'Mencionarlo a TI y esperar a que ellos lo implementen', en: 'Mention it to IT and wait for them to implement it', fr: 'Le mentionner à l\'informatique et attendre qu\'ils le mettent en œuvre' }, value: 25 }, { id: 'd', text: { es: 'Intentar automatizar todos los procesos de una vez sin piloto previo', en: 'Try to automate all processes at once without a prior pilot', fr: 'Essayer d\'automatiser tous les processus d\'un coup sans pilote préalable' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-office-rd-4', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-cloud-tools', type: 'scale', content: { es: '¿Qué tan dispuesto está a aprender nuevas herramientas y funcionalidades de Microsoft 365 que podrían cambiar su forma actual de trabajar?', en: 'How willing are you to learn new Microsoft 365 tools and features that could change your current way of working?', fr: 'Dans quelle mesure êtes-vous disposé à apprendre de nouveaux outils et fonctionnalités de Microsoft 365 qui pourraient changer votre façon actuelle de travailler ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero mantener mis métodos actuales de trabajo', en: 'I prefer to maintain my current work methods', fr: 'Je préfère maintenir mes méthodes de travail actuelles' }, max: { es: 'Busco activamente nuevas herramientas y funcionalidades para mejorar mi productividad', en: 'I actively seek new tools and features to improve my productivity', fr: 'Je cherche activement de nouveaux outils et fonctionnalités pour améliorer ma productivité' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-office-rd-5', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-ai-copilot', type: 'scenario', content: { es: 'Su empresa acaba de implementar Microsoft 365 Copilot para todo el personal administrativo. Después de dos semanas, nota que la mayoría de sus compañeros no lo están utilizando porque no saben cómo funciona o le tienen desconfianza. Su jefe le pide que lidere una iniciativa para aumentar la adopción de Copilot en el departamento.\n\nDescriba su plan para promover la adopción, incluyendo cómo abordaría las resistencias, qué casos de uso destacaría y cómo mediría el éxito de la iniciativa.', en: 'Your company has just implemented Microsoft 365 Copilot for all administrative staff. After two weeks, you notice that most of your colleagues are not using it because they don\'t know how it works or distrust it. Your boss asks you to lead an initiative to increase Copilot adoption in the department.\n\nDescribe your plan to promote adoption, including how you would address resistance, what use cases you would highlight, and how you would measure the initiative\'s success.', fr: 'Votre entreprise vient d\'implémenter Microsoft 365 Copilot pour tout le personnel administratif. Après deux semaines, vous remarquez que la plupart de vos collègues ne l\'utilisent pas car ils ne savent pas comment il fonctionne ou s\'en méfient. Votre chef vous demande de mener une initiative pour augmenter l\'adoption de Copilot dans le département.\n\nDécrivez votre plan pour promouvoir l\'adoption, comment vous aborderiez les résistances, quels cas d\'usage vous mettriez en avant et comment vous mesureriez le succès.' }, rubric: { es: 'Evaluar: (1) Comprensión de las resistencias al cambio tecnológico, (2) Plan de capacitación progresiva con casos de uso prácticos, (3) Identificación de embajadores y early adopters, (4) Casos de uso relevantes para el departamento, (5) Métricas de adopción y éxito, (6) Comunicación empática y liderazgo.', en: 'Evaluate: (1) Understanding of technology change resistance, (2) Progressive training plan with practical use cases, (3) Identification of ambassadors and early adopters, (4) Relevant use cases for the department, (5) Adoption and success metrics, (6) Empathetic communication and leadership.', fr: 'Évaluer : (1) Compréhension des résistances au changement technologique, (2) Plan de formation progressif avec cas d\'usage pratiques, (3) Identification d\'ambassadeurs, (4) Cas d\'usage pertinents pour le département, (5) Métriques d\'adoption et de succès, (6) Communication empathique et leadership.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-office-rd-6', profileId: 'ms-office-user', categoryId: 'ms-office-readiness', competencyId: 'ms-office-workflow-optimization', type: 'open-text', content: { es: 'Describa un flujo de trabajo o proceso administrativo que haya optimizado utilizando herramientas de Microsoft 365 (por ejemplo, automatizaciones con Power Automate, formularios con Forms, dashboards con Power BI, listas en SharePoint). Explique cómo era el proceso antes, qué cambios implementó y qué mejoras logró.', en: 'Describe a workflow or administrative process that you have optimized using Microsoft 365 tools (for example, automations with Power Automate, forms with Forms, dashboards with Power BI, lists in SharePoint). Explain what the process was like before, what changes you implemented, and what improvements you achieved.', fr: 'Décrivez un flux de travail ou processus administratif que vous avez optimisé en utilisant les outils Microsoft 365 (par exemple, automatisations avec Power Automate, formulaires avec Forms, tableaux de bord avec Power BI, listes dans SharePoint). Expliquez comment était le processus avant, quels changements vous avez implémentés et quelles améliorations vous avez obtenues.' }, rubric: { es: 'Evaluar: (1) Comprensión del proceso original y sus ineficiencias, (2) Selección apropiada de herramientas M365, (3) Implementación técnica descrita, (4) Mejoras cuantificables logradas, (5) Adopción por parte del equipo, (6) Visión de mejora continua.', en: 'Evaluate: (1) Understanding of original process and its inefficiencies, (2) Appropriate M365 tool selection, (3) Technical implementation described, (4) Quantifiable improvements achieved, (5) Team adoption, (6) Continuous improvement vision.', fr: 'Évaluer : (1) Compréhension du processus original et de ses inefficacités, (2) Sélection appropriée des outils M365, (3) Implémentation technique décrite, (4) Améliorations quantifiables obtenues, (5) Adoption par l\'équipe, (6) Vision d\'amélioration continue.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
// MICROSOFT SHAREPOINT USER QUESTIONS
// ============================================================================

// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msSpProfessionalQuestions: Question[] = [
  { id: 'ms-sp-prof-1', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-site-mgmt', type: 'multiple-choice', content: { es: 'Le piden crear un nuevo sitio de SharePoint para un proyecto interdepartamental que durará 6 meses. Participarán 25 personas de 4 departamentos. ¿Cuál es el enfoque más apropiado?', en: 'You are asked to create a new SharePoint site for a cross-departmental project lasting 6 months. Twenty-five people from 4 departments will participate. What is the most appropriate approach?', fr: 'On vous demande de créer un nouveau site SharePoint pour un projet interdépartemental de 6 mois. Vingt-cinq personnes de 4 départements participeront. Quelle est l\'approche la plus appropriée ?' }, options: [{ id: 'a', text: { es: 'Crear un sitio de equipo (Team Site) con estructura de bibliotecas por departamento, configurar la navegación clara, establecer metadatos para clasificación de documentos, crear un canal de Teams vinculado y definir la estructura de permisos por grupo', en: 'Create a Team Site with document library structure by department, configure clear navigation, establish metadata for document classification, create a linked Teams channel, and define permission structure by group', fr: 'Créer un site d\'équipe (Team Site) avec une structure de bibliothèques par département, configurer la navigation claire, établir des métadonnées pour la classification des documents, créer un canal Teams lié et définir la structure des permissions par groupe' }, value: 100 }, { id: 'b', text: { es: 'Crear una carpeta compartida en OneDrive y dar acceso a todos', en: 'Create a shared folder in OneDrive and give everyone access', fr: 'Créer un dossier partagé dans OneDrive et donner accès à tous' }, value: 0 }, { id: 'c', text: { es: 'Crear un sitio básico sin estructura y dejar que los usuarios organicen el contenido como prefieran', en: 'Create a basic site without structure and let users organize content as they prefer', fr: 'Créer un site basique sans structure et laisser les utilisateurs organiser le contenu comme ils le préfèrent' }, value: 0 }, { id: 'd', text: { es: 'Crear un sitio de comunicación con páginas informativas pero sin bibliotecas de documentos compartidas', en: 'Create a communication site with informational pages but without shared document libraries', fr: 'Créer un site de communication avec des pages informatives mais sans bibliothèques de documents partagées' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-sp-prof-2', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-document-mgmt', type: 'multiple-choice', content: { es: 'La biblioteca de documentos de su departamento en SharePoint tiene más de 2,000 archivos sin estructura clara. Los usuarios se quejan de que no encuentran los documentos que necesitan. ¿Cómo mejoraría la situación?', en: 'Your department\'s SharePoint document library has over 2,000 files with no clear structure. Users complain they can\'t find the documents they need. How would you improve the situation?', fr: 'La bibliothèque de documents de votre département dans SharePoint contient plus de 2 000 fichiers sans structure claire. Les utilisateurs se plaignent de ne pas trouver les documents nécessaires. Comment amélioreriez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Implementar columnas de metadatos (tipo de documento, departamento, estado, fecha), crear vistas filtradas por categoría, establecer una convención de nombres y capacitar al equipo en su uso', en: 'Implement metadata columns (document type, department, status, date), create filtered views by category, establish a naming convention, and train the team on its use', fr: 'Implémenter des colonnes de métadonnées (type de document, département, statut, date), créer des vues filtrées par catégorie, établir une convention de nommage et former l\'équipe à son utilisation' }, value: 100 }, { id: 'b', text: { es: 'Crear muchas subcarpetas para organizar los archivos por tema', en: 'Create many subfolders to organize files by topic', fr: 'Créer de nombreux sous-dossiers pour organiser les fichiers par thème' }, value: 25 }, { id: 'c', text: { es: 'Eliminar todos los archivos antiguos y empezar de nuevo', en: 'Delete all old files and start over', fr: 'Supprimer tous les anciens fichiers et recommencer' }, value: 0 }, { id: 'd', text: { es: 'Decirle a los usuarios que utilicen la función de búsqueda y dejar la biblioteca como está', en: 'Tell users to use the search function and leave the library as is', fr: 'Dire aux utilisateurs d\'utiliser la fonction de recherche et laisser la bibliothèque telle quelle' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-sp-prof-3', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-lists-workflows', type: 'multiple-choice', content: { es: 'Su departamento necesita un sistema para rastrear solicitudes de vacaciones: los empleados envían solicitudes, el supervisor aprueba o rechaza, y recursos humanos registra los días. ¿Cómo lo implementaría en SharePoint?', en: 'Your department needs a system to track vacation requests: employees submit requests, supervisors approve or reject, and HR records the days. How would you implement it in SharePoint?', fr: 'Votre département a besoin d\'un système pour suivre les demandes de vacances : les employés soumettent des demandes, le superviseur approuve ou rejette, et les RH enregistrent les jours. Comment l\'implément eriez-vous dans SharePoint ?' }, options: [{ id: 'a', text: { es: 'Crear una lista de SharePoint con columnas para empleado, fechas, tipo de ausencia y estado, configurar un flujo de Power Automate para notificaciones y aprobaciones automáticas, y crear vistas personalizadas para cada rol', en: 'Create a SharePoint list with columns for employee, dates, absence type, and status, configure a Power Automate flow for notifications and automatic approvals, and create custom views for each role', fr: 'Créer une liste SharePoint avec des colonnes pour l\'employé, les dates, le type d\'absence et le statut, configurer un flux Power Automate pour les notifications et approbations automatiques, et créer des vues personnalisées pour chaque rôle' }, value: 100 }, { id: 'b', text: { es: 'Usar un archivo de Excel compartido donde todos escriban sus solicitudes', en: 'Use a shared Excel file where everyone writes their requests', fr: 'Utiliser un fichier Excel partagé où tout le monde écrit ses demandes' }, value: 0 }, { id: 'c', text: { es: 'Enviar solicitudes por correo electrónico y llevar el control manualmente', en: 'Send requests by email and keep track manually', fr: 'Envoyer les demandes par courriel et suivre manuellement' }, value: 0 }, { id: 'd', text: { es: 'Crear una lista básica sin flujo de aprobación automatizado', en: 'Create a basic list without an automated approval flow', fr: 'Créer une liste basique sans flux d\'approbation automatisé' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-sp-prof-4', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-permissions', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene configurando y gestionando permisos en SharePoint (grupos de seguridad, niveles de permiso, herencia, acceso externo)?', en: 'What level of experience do you have configuring and managing permissions in SharePoint (security groups, permission levels, inheritance, external access)?', fr: 'Quel niveau d\'expérience avez-vous dans la configuration et la gestion des permissions dans SharePoint (groupes de sécurité, niveaux de permission, héritage, accès externe) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No tengo experiencia gestionando permisos en SharePoint', en: 'I have no experience managing SharePoint permissions', fr: 'Je n\'ai aucune expérience dans la gestion des permissions SharePoint' }, max: { es: 'Gestiono permisos complejos incluyendo acceso externo, grupos dinámicos y políticas de seguridad', en: 'I manage complex permissions including external access, dynamic groups, and security policies', fr: 'Je gère des permissions complexes incluant l\'accès externe, les groupes dynamiques et les politiques de sécurité' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-sp-prof-5', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-document-mgmt', type: 'scenario', content: { es: 'Su empresa necesita implementar un sistema de gestión documental en SharePoint para cumplir con regulaciones de la industria que requieren: control de versiones obligatorio, retención de documentos por 7 años, etiquetas de clasificación de confidencialidad (público, interno, confidencial, restringido) y auditoría de acceso. Actualmente los documentos están dispersos en carpetas locales, correos y USB de los empleados.\n\nDescriba su plan de implementación, incluyendo la estructura del sitio, políticas de retención, clasificación de documentos y plan de migración.', en: 'Your company needs to implement a document management system in SharePoint to comply with industry regulations requiring: mandatory version control, 7-year document retention, confidentiality classification labels (public, internal, confidential, restricted), and access auditing. Currently documents are scattered across local folders, emails, and employee USB drives.\n\nDescribe your implementation plan, including site structure, retention policies, document classification, and migration plan.', fr: 'Votre entreprise doit implémenter un système de gestion documentaire dans SharePoint pour se conformer aux réglementations de l\'industrie exigeant : contrôle de version obligatoire, rétention des documents pendant 7 ans, étiquettes de classification de confidentialité (public, interne, confidentiel, restreint) et audit d\'accès. Actuellement, les documents sont dispersés dans des dossiers locaux, des courriels et des clés USB.\n\nDécrivez votre plan d\'implémentation, incluant la structure du site, les politiques de rétention, la classification des documents et le plan de migration.' }, rubric: { es: 'Evaluar: (1) Estructura de sitios y bibliotecas propuesta, (2) Configuración de control de versiones y check-in/check-out, (3) Implementación de políticas de retención, (4) Sistema de etiquetas de confidencialidad, (5) Plan de migración ordenado y priorizado, (6) Capacitación y gestión del cambio.', en: 'Evaluate: (1) Proposed site and library structure, (2) Version control and check-in/check-out configuration, (3) Retention policy implementation, (4) Confidentiality label system, (5) Orderly and prioritized migration plan, (6) Training and change management.', fr: 'Évaluer : (1) Structure de sites et bibliothèques proposée, (2) Configuration du contrôle de version, (3) Implémentation des politiques de rétention, (4) Système d\'étiquettes de confidentialité, (5) Plan de migration ordonné, (6) Formation et gestion du changement.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-sp-prof-6', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-professional', competencyId: 'ms-sp-lists-workflows', type: 'open-text', content: { es: 'Describa los tipos de listas y flujos de trabajo que ha creado o administrado en SharePoint. Incluya ejemplos específicos de listas personalizadas, columnas calculadas, vistas filtradas y flujos de aprobación o notificación que haya implementado.', en: 'Describe the types of lists and workflows you have created or managed in SharePoint. Include specific examples of custom lists, calculated columns, filtered views, and approval or notification flows you have implemented.', fr: 'Décrivez les types de listes et flux de travail que vous avez créés ou gérés dans SharePoint. Incluez des exemples spécifiques de listes personnalisées, colonnes calculées, vues filtrées et flux d\'approbation ou de notification que vous avez implémentés.' }, rubric: { es: 'Evaluar: (1) Variedad de listas y propósitos implementados, (2) Complejidad de las columnas y fórmulas utilizadas, (3) Diseño efectivo de vistas y filtros, (4) Flujos de trabajo funcionales y útiles, (5) Integración con otras herramientas M365, (6) Beneficios demostrados para el equipo.', en: 'Evaluate: (1) Variety of lists and purposes implemented, (2) Complexity of columns and formulas used, (3) Effective view and filter design, (4) Functional and useful workflows, (5) Integration with other M365 tools, (6) Demonstrated benefits for the team.', fr: 'Évaluer : (1) Variété des listes et objectifs implémentés, (2) Complexité des colonnes et formules utilisées, (3) Conception efficace des vues et filtres, (4) Flux de travail fonctionnels et utiles, (5) Intégration avec d\'autres outils M365, (6) Bénéfices démontrés pour l\'équipe.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msSpSoftSkillsQuestions: Question[] = [
  { id: 'ms-sp-ss-1', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-info-architecture', type: 'multiple-choice', content: { es: 'Le piden reorganizar la intranet corporativa en SharePoint que tiene 15 sitios departamentales sin una estructura coherente. Los empleados se quejan de que no encuentran información. ¿Por dónde empieza?', en: 'You are asked to reorganize the corporate intranet in SharePoint which has 15 departmental sites without a coherent structure. Employees complain they can\'t find information. Where do you start?', fr: 'On vous demande de réorganiser l\'intranet corporatif dans SharePoint qui comporte 15 sites départementaux sans structure cohérente. Les employés se plaignent de ne pas trouver d\'informations. Par où commencez-vous ?' }, options: [{ id: 'a', text: { es: 'Realizar un inventario de contenido existente, entrevistar a usuarios de cada departamento sobre sus necesidades, diseñar una taxonomía y arquitectura de información unificada, crear un mapa del sitio propuesto y validarlo con los stakeholders antes de implementar', en: 'Conduct an inventory of existing content, interview users from each department about their needs, design a unified taxonomy and information architecture, create a proposed site map, and validate with stakeholders before implementing', fr: 'Réaliser un inventaire du contenu existant, interviewer les utilisateurs de chaque département sur leurs besoins, concevoir une taxonomie et architecture d\'information unifiée, créer un plan de site proposé et valider avec les parties prenantes avant d\'implémenter' }, value: 100 }, { id: 'b', text: { es: 'Eliminar todos los sitios existentes y crear uno nuevo desde cero', en: 'Delete all existing sites and create a new one from scratch', fr: 'Supprimer tous les sites existants et en créer un nouveau à partir de zéro' }, value: 0 }, { id: 'c', text: { es: 'Agregar una barra de búsqueda más visible y dejar los sitios como están', en: 'Add a more visible search bar and leave the sites as they are', fr: 'Ajouter une barre de recherche plus visible et laisser les sites tels quels' }, value: 0 }, { id: 'd', text: { es: 'Reorganizar los sitios según su propio criterio sin consultar a los usuarios', en: 'Reorganize the sites based on your own criteria without consulting users', fr: 'Réorganiser les sites selon vos propres critères sans consulter les utilisateurs' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-sp-ss-2', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-training-support', type: 'multiple-choice', content: { es: 'Acaban de migrar a SharePoint Online y varios empleados de mayor antigüedad están frustrados porque no entienden la nueva plataforma y prefieren el sistema anterior de carpetas compartidas. ¿Cómo aborda la situación?', en: 'Your company just migrated to SharePoint Online and several senior employees are frustrated because they don\'t understand the new platform and prefer the old shared folder system. How do you approach the situation?', fr: 'Votre entreprise vient de migrer vers SharePoint Online et plusieurs employés anciens sont frustrés car ils ne comprennent pas la nouvelle plateforme et préfèrent l\'ancien système de dossiers partagés. Comment abordez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Escuchar sus frustraciones con empatía, crear guías visuales paso a paso adaptadas a su nivel, ofrecer sesiones de capacitación en grupos pequeños, mostrarles los beneficios prácticos y dar seguimiento personalizado', en: 'Listen to their frustrations with empathy, create step-by-step visual guides adapted to their level, offer small-group training sessions, show them practical benefits, and provide personalized follow-up', fr: 'Écouter leurs frustrations avec empathie, créer des guides visuels pas à pas adaptés à leur niveau, offrir des sessions de formation en petits groupes, leur montrer les avantages pratiques et assurer un suivi personnalisé' }, value: 100 }, { id: 'b', text: { es: 'Enviarles el manual de usuario de Microsoft y decirles que lo lean', en: 'Send them the Microsoft user manual and tell them to read it', fr: 'Leur envoyer le manuel d\'utilisateur Microsoft et leur dire de le lire' }, value: 0 }, { id: 'c', text: { es: 'Decirles que deben adaptarse porque es una decisión de la empresa', en: 'Tell them they must adapt because it\'s a company decision', fr: 'Leur dire qu\'ils doivent s\'adapter car c\'est une décision de l\'entreprise' }, value: 0 }, { id: 'd', text: { es: 'Crear una capacitación general para toda la empresa sin personalizar', en: 'Create a general training for the whole company without personalizing', fr: 'Créer une formation générale pour toute l\'entreprise sans personnaliser' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-sp-ss-3', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-cross-team', type: 'multiple-choice', content: { es: 'Dos departamentos quieren usar el mismo sitio de SharePoint pero tienen requerimientos de permisos contradictorios: Marketing quiere que todo sea visible para todos, mientras que Legal requiere que ciertos documentos sean accesibles solo para su equipo. ¿Cómo resuelve el conflicto?', en: 'Two departments want to use the same SharePoint site but have conflicting permission requirements: Marketing wants everything visible to everyone, while Legal requires certain documents to be accessible only to their team. How do you resolve the conflict?', fr: 'Deux départements veulent utiliser le même site SharePoint mais ont des exigences de permissions contradictoires : le Marketing veut que tout soit visible pour tous, tandis que le Juridique exige que certains documents soient accessibles uniquement à leur équipe. Comment résolvez-vous le conflit ?' }, options: [{ id: 'a', text: { es: 'Crear bibliotecas separadas dentro del mismo sitio con permisos diferenciados: una biblioteca general accesible para todos y una biblioteca restringida para Legal con herencia de permisos rota, explicando a ambos equipos la solución', en: 'Create separate libraries within the same site with differentiated permissions: a general library accessible to all and a restricted library for Legal with broken permission inheritance, explaining the solution to both teams', fr: 'Créer des bibliothèques séparées au sein du même site avec des permissions différenciées : une bibliothèque générale accessible à tous et une bibliothèque restreinte pour le Juridique avec héritage de permissions rompu, en expliquant la solution aux deux équipes' }, value: 100 }, { id: 'b', text: { es: 'Dar acceso completo a todos y confiar en que Legal protegerá sus documentos por su cuenta', en: 'Give full access to everyone and trust that Legal will protect their documents on their own', fr: 'Donner un accès complet à tous et espérer que le Juridique protégera ses documents par lui-même' }, value: 0 }, { id: 'c', text: { es: 'Crear dos sitios completamente separados sin ningún contenido compartido', en: 'Create two completely separate sites with no shared content', fr: 'Créer deux sites complètement séparés sans aucun contenu partagé' }, value: 25 }, { id: 'd', text: { es: 'Restringir todo el sitio a los permisos más restrictivos para cumplir con Legal', en: 'Restrict the entire site to the most restrictive permissions to comply with Legal', fr: 'Restreindre tout le site aux permissions les plus restrictives pour se conformer au Juridique' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-sp-ss-4', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-training-support', type: 'scale', content: { es: '¿Qué tan cómodo se siente capacitando a otros usuarios en el uso de SharePoint y resolviendo sus dudas técnicas?', en: 'How comfortable do you feel training other users on SharePoint usage and resolving their technical questions?', fr: 'À quel point vous sentez-vous à l\'aise pour former d\'autres utilisateurs à l\'utilisation de SharePoint et résoudre leurs questions techniques ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No me siento preparado para capacitar a otros en SharePoint', en: 'I don\'t feel prepared to train others on SharePoint', fr: 'Je ne me sens pas prêt à former d\'autres personnes sur SharePoint' }, max: { es: 'Capacito regularmente a usuarios de todos los niveles y resuelvo problemas complejos', en: 'I regularly train users of all levels and resolve complex issues', fr: 'Je forme régulièrement des utilisateurs de tous niveaux et résous des problèmes complexes' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-sp-ss-5', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-cross-team', type: 'scenario', content: { es: 'La empresa ha decidido consolidar todos los sitios departamentales de SharePoint bajo una nueva arquitectura unificada. Usted es el responsable de coordinar con los 6 jefes de departamento que tienen ideas muy diferentes sobre cómo debe organizarse la información. Algunos quieren mantener su autonomía completa, otros quieren estandarizar todo, y dos departamentos tienen conflictos previos sobre acceso a información compartida.\n\nDescriba cómo facilitaría el proceso de consenso, qué compromisos propondría y cómo aseguraría que la nueva estructura satisfaga las necesidades de todos.', en: 'The company has decided to consolidate all departmental SharePoint sites under a new unified architecture. You are responsible for coordinating with 6 department heads who have very different ideas about how information should be organized. Some want to maintain complete autonomy, others want to standardize everything, and two departments have prior conflicts about shared information access.\n\nDescribe how you would facilitate the consensus process, what compromises you would propose, and how you would ensure the new structure meets everyone\'s needs.', fr: 'L\'entreprise a décidé de consolider tous les sites départementaux SharePoint sous une nouvelle architecture unifiée. Vous êtes responsable de la coordination avec 6 chefs de département qui ont des idées très différentes sur l\'organisation de l\'information. Certains veulent maintenir leur autonomie complète, d\'autres veulent tout standardiser, et deux départements ont des conflits antérieurs.\n\nDécrivez comment vous faciliteriez le processus de consensus, quels compromis vous proposeriez et comment vous assureriez que la nouvelle structure satisfait les besoins de tous.' }, rubric: { es: 'Evaluar: (1) Habilidad de facilitación y escucha activa, (2) Propuesta de modelo híbrido que equilibre autonomía y estandarización, (3) Resolución de conflictos entre departamentos, (4) Gobernanza clara y roles definidos, (5) Plan de implementación gradual, (6) Mecanismos de retroalimentación y ajuste.', en: 'Evaluate: (1) Facilitation and active listening skills, (2) Hybrid model proposal balancing autonomy and standardization, (3) Conflict resolution between departments, (4) Clear governance and defined roles, (5) Gradual implementation plan, (6) Feedback and adjustment mechanisms.', fr: 'Évaluer : (1) Compétences de facilitation et d\'écoute active, (2) Proposition de modèle hybride équilibrant autonomie et standardisation, (3) Résolution de conflits entre départements, (4) Gouvernance claire et rôles définis, (5) Plan d\'implémentation graduel, (6) Mécanismes de rétroaction et d\'ajustement.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-sp-ss-6', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-soft-skills', competencyId: 'ms-sp-info-architecture', type: 'open-text', content: { es: 'Describa su enfoque para diseñar la arquitectura de información de un sitio SharePoint corporativo. ¿Qué factores considera, cómo decide entre usar sitios, subsitios, bibliotecas o listas, y cómo asegura que la estructura sea intuitiva para usuarios no técnicos?', en: 'Describe your approach to designing the information architecture of a corporate SharePoint site. What factors do you consider, how do you decide between using sites, subsites, libraries, or lists, and how do you ensure the structure is intuitive for non-technical users?', fr: 'Décrivez votre approche pour concevoir l\'architecture de l\'information d\'un site SharePoint corporatif. Quels facteurs considérez-vous, comment décidez-vous entre l\'utilisation de sites, sous-sites, bibliothèques ou listes, et comment vous assurez-vous que la structure est intuitive pour les utilisateurs non techniques ?' }, rubric: { es: 'Evaluar: (1) Metodología de análisis de necesidades, (2) Criterios para elegir entre tipos de contenedores, (3) Principios de usabilidad y encontrabilidad, (4) Consideración de escalabilidad y mantenimiento, (5) Involucrar a usuarios en el diseño, (6) Buenas prácticas de SharePoint aplicadas.', en: 'Evaluate: (1) Needs analysis methodology, (2) Criteria for choosing between container types, (3) Usability and findability principles, (4) Scalability and maintenance considerations, (5) User involvement in design, (6) SharePoint best practices applied.', fr: 'Évaluer : (1) Méthodologie d\'analyse des besoins, (2) Critères de choix entre types de conteneurs, (3) Principes d\'utilisabilité et de trouvabilité, (4) Considérations de scalabilité et maintenance, (5) Implication des utilisateurs dans la conception, (6) Bonnes pratiques SharePoint appliquées.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const msSpReadinessQuestions: Question[] = [
  { id: 'ms-sp-rd-1', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-modern-experience', type: 'multiple-choice', content: { es: 'Microsoft está migrando las páginas clásicas de SharePoint a la experiencia moderna. Varios sitios de su empresa aún usan la interfaz clásica. ¿Cómo abordaría la transición?', en: 'Microsoft is migrating classic SharePoint pages to the modern experience. Several of your company\'s sites still use the classic interface. How would you approach the transition?', fr: 'Microsoft migre les pages classiques de SharePoint vers l\'expérience moderne. Plusieurs sites de votre entreprise utilisent encore l\'interface classique. Comment aborderiez-vous la transition ?' }, options: [{ id: 'a', text: { es: 'Inventariar los sitios clásicos, evaluar cuáles pueden migrarse directamente, identificar personalizaciones que requieren adaptación, crear un plan de migración por fases y aprovechar las nuevas capacidades de la experiencia moderna como web parts mejorados', en: 'Inventory classic sites, evaluate which can be directly migrated, identify customizations requiring adaptation, create a phased migration plan, and leverage new modern experience capabilities like improved web parts', fr: 'Inventorier les sites classiques, évaluer lesquels peuvent être migrés directement, identifier les personnalisations nécessitant une adaptation, créer un plan de migration par phases et tirer parti des nouvelles capacités de l\'expérience moderne comme les composants web améliorés' }, value: 100 }, { id: 'b', text: { es: 'Mantener los sitios clásicos mientras funcionen y migrar solo cuando Microsoft los desactive', en: 'Keep classic sites as long as they work and migrate only when Microsoft deactivates them', fr: 'Garder les sites classiques tant qu\'ils fonctionnent et migrer uniquement quand Microsoft les désactivera' }, value: 0 }, { id: 'c', text: { es: 'Migrar todos los sitios de una vez sin planificación previa', en: 'Migrate all sites at once without prior planning', fr: 'Migrer tous les sites d\'un coup sans planification préalable' }, value: 0 }, { id: 'd', text: { es: 'Migrar solo los sitios más visibles y dejar los demás en formato clásico', en: 'Migrate only the most visible sites and leave the rest in classic format', fr: 'Migrer uniquement les sites les plus visibles et laisser les autres en format classique' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'ms-sp-rd-2', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-power-platform', type: 'multiple-choice', content: { es: 'Su empresa quiere extender las capacidades de SharePoint integrando Power Apps para formularios personalizados y Power BI para dashboards de datos. Le piden explorar estas posibilidades. ¿Cómo procede?', en: 'Your company wants to extend SharePoint capabilities by integrating Power Apps for custom forms and Power BI for data dashboards. You are asked to explore these possibilities. How do you proceed?', fr: 'Votre entreprise souhaite étendre les capacités de SharePoint en intégrant Power Apps pour des formulaires personnalisés et Power BI pour des tableaux de bord de données. On vous demande d\'explorer ces possibilités. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Estudiar los fundamentos de Power Apps y Power BI a través de Microsoft Learn, crear prototipos con datos de prueba, demostrar casos de uso prácticos al equipo y proponer un proyecto piloto con métricas de éxito definidas', en: 'Study Power Apps and Power BI fundamentals through Microsoft Learn, create prototypes with test data, demonstrate practical use cases to the team, and propose a pilot project with defined success metrics', fr: 'Étudier les fondamentaux de Power Apps et Power BI via Microsoft Learn, créer des prototypes avec des données de test, démontrer des cas d\'usage pratiques à l\'équipe et proposer un projet pilote avec des métriques de succès définies' }, value: 100 }, { id: 'b', text: { es: 'Indicar que esas herramientas son responsabilidad del equipo de desarrollo y no del usuario de SharePoint', en: 'Indicate that those tools are the development team\'s responsibility and not the SharePoint user\'s', fr: 'Indiquer que ces outils sont la responsabilité de l\'équipe de développement et non de l\'utilisateur SharePoint' }, value: 0 }, { id: 'c', text: { es: 'Contratar un consultor externo para que haga todo el trabajo', en: 'Hire an external consultant to do all the work', fr: 'Engager un consultant externe pour faire tout le travail' }, value: 25 }, { id: 'd', text: { es: 'Intentar implementar soluciones complejas inmediatamente sin capacitación previa', en: 'Try to implement complex solutions immediately without prior training', fr: 'Essayer d\'implémenter des solutions complexes immédiatement sans formation préalable' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'ms-sp-rd-3', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-ai-copilot', type: 'multiple-choice', content: { es: 'Microsoft SharePoint Premium introduce capacidades de IA como procesamiento inteligente de documentos, resúmenes automáticos y búsqueda semántica avanzada. Su empresa está evaluando si invertir en estas funcionalidades. Le piden su opinión. ¿Qué recomienda?', en: 'Microsoft SharePoint Premium introduces AI capabilities like intelligent document processing, automatic summaries, and advanced semantic search. Your company is evaluating whether to invest in these features. You are asked for your opinion. What do you recommend?', fr: 'Microsoft SharePoint Premium introduit des capacités d\'IA comme le traitement intelligent des documents, les résumés automatiques et la recherche sémantique avancée. Votre entreprise évalue s\'il faut investir dans ces fonctionnalités. On vous demande votre avis. Que recommandez-vous ?' }, options: [{ id: 'a', text: { es: 'Analizar los volúmenes documentales de la empresa, identificar procesos que se beneficiarían de IA, realizar una prueba de concepto con un caso de uso concreto, calcular el ROI potencial y presentar una recomendación fundamentada con datos', en: 'Analyze the company\'s document volumes, identify processes that would benefit from AI, conduct a proof of concept with a concrete use case, calculate potential ROI, and present a data-backed recommendation', fr: 'Analyser les volumes documentaires de l\'entreprise, identifier les processus qui bénéficieraient de l\'IA, réaliser une preuve de concept avec un cas d\'usage concret, calculer le ROI potentiel et présenter une recommandation étayée par des données' }, value: 100 }, { id: 'b', text: { es: 'Recomendar no invertir porque la IA aún no es confiable', en: 'Recommend not investing because AI is not yet reliable', fr: 'Recommander de ne pas investir car l\'IA n\'est pas encore fiable' }, value: 0 }, { id: 'c', text: { es: 'Recomendar comprar todas las licencias Premium inmediatamente', en: 'Recommend buying all Premium licenses immediately', fr: 'Recommander d\'acheter immédiatement toutes les licences Premium' }, value: 25 }, { id: 'd', text: { es: 'Decir que no tiene suficiente conocimiento para opinar', en: 'Say you don\'t have enough knowledge to give an opinion', fr: 'Dire que vous n\'avez pas assez de connaissances pour donner un avis' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'ms-sp-rd-4', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-modern-experience', type: 'scale', content: { es: '¿Qué tan actualizado se mantiene sobre las nuevas funcionalidades y mejoras que Microsoft lanza para SharePoint Online?', en: 'How up to date do you stay on new features and improvements that Microsoft releases for SharePoint Online?', fr: 'À quel point restez-vous à jour sur les nouvelles fonctionnalités et améliorations que Microsoft publie pour SharePoint Online ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No sigo las actualizaciones de SharePoint', en: 'I don\'t follow SharePoint updates', fr: 'Je ne suis pas les mises à jour de SharePoint' }, max: { es: 'Sigo activamente el roadmap de Microsoft, participo en la comunidad y pruebo nuevas funcionalidades cuando se lanzan', en: 'I actively follow the Microsoft roadmap, participate in the community, and test new features when released', fr: 'Je suis activement la feuille de route Microsoft, participe à la communauté et teste les nouvelles fonctionnalités dès leur lancement' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'ms-sp-rd-5', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-power-platform', type: 'scenario', content: { es: 'Su empresa quiere crear un portal de autoservicio para empleados en SharePoint que integre: formularios de solicitudes (vacaciones, viáticos, TI) con Power Apps, flujos de aprobación con Power Automate, un dashboard de métricas de recursos humanos con Power BI embebido, y un chatbot con Power Virtual Agents para preguntas frecuentes. Usted es designado como líder técnico del proyecto.\n\nDescriba su plan de implementación, las fases del proyecto, cómo priorizaría las funcionalidades y qué riesgos anticipa.', en: 'Your company wants to create an employee self-service portal in SharePoint that integrates: request forms (vacation, expenses, IT) with Power Apps, approval flows with Power Automate, an HR metrics dashboard with embedded Power BI, and a chatbot with Power Virtual Agents for FAQs. You are designated as the technical lead for the project.\n\nDescribe your implementation plan, project phases, how you would prioritize features, and what risks you anticipate.', fr: 'Votre entreprise veut créer un portail en libre-service pour les employés dans SharePoint intégrant : des formulaires de demande (vacances, frais, IT) avec Power Apps, des flux d\'approbation avec Power Automate, un tableau de bord de métriques RH avec Power BI intégré, et un chatbot avec Power Virtual Agents pour les FAQ. Vous êtes désigné comme responsable technique du projet.\n\nDécrivez votre plan d\'implémentation, les phases du projet, comment vous prioriseriez les fonctionnalités et quels risques vous anticipez.' }, rubric: { es: 'Evaluar: (1) Plan de implementación por fases realista, (2) Priorización basada en impacto y complejidad, (3) Integración coherente entre las herramientas Power Platform, (4) Consideraciones de UX y adopción, (5) Identificación de riesgos técnicos y organizacionales, (6) Métricas de éxito y plan de mantenimiento.', en: 'Evaluate: (1) Realistic phased implementation plan, (2) Prioritization based on impact and complexity, (3) Coherent integration between Power Platform tools, (4) UX and adoption considerations, (5) Technical and organizational risk identification, (6) Success metrics and maintenance plan.', fr: 'Évaluer : (1) Plan d\'implémentation par phases réaliste, (2) Priorisation basée sur l\'impact et la complexité, (3) Intégration cohérente entre les outils Power Platform, (4) Considérations UX et adoption, (5) Identification des risques techniques et organisationnels, (6) Métriques de succès et plan de maintenance.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'ms-sp-rd-6', profileId: 'ms-sharepoint-user', categoryId: 'ms-sp-readiness', competencyId: 'ms-sp-ai-copilot', type: 'open-text', content: { es: 'Describa su visión sobre cómo la inteligencia artificial y las herramientas como Microsoft Copilot transformarán la gestión de contenido y la colaboración en SharePoint en los próximos años. ¿Qué oportunidades ve para su organización y qué preparación considera necesaria?', en: 'Describe your vision of how artificial intelligence and tools like Microsoft Copilot will transform content management and collaboration in SharePoint in the coming years. What opportunities do you see for your organization and what preparation do you consider necessary?', fr: 'Décrivez votre vision de comment l\'intelligence artificielle et les outils comme Microsoft Copilot transformeront la gestion de contenu et la collaboration dans SharePoint dans les années à venir. Quelles opportunités voyez-vous pour votre organisation et quelle préparation considérez-vous nécessaire ?' }, rubric: { es: 'Evaluar: (1) Comprensión de las capacidades actuales y futuras de IA en SharePoint, (2) Visión estratégica para la organización, (3) Oportunidades identificadas con casos de uso concretos, (4) Comprensión de los requisitos de preparación (datos limpios, gobernanza, capacitación), (5) Consideraciones éticas y de privacidad, (6) Plan de acción propuesto.', en: 'Evaluate: (1) Understanding of current and future AI capabilities in SharePoint, (2) Strategic vision for the organization, (3) Identified opportunities with concrete use cases, (4) Understanding of preparation requirements (clean data, governance, training), (5) Ethical and privacy considerations, (6) Proposed action plan.', fr: 'Évaluer : (1) Compréhension des capacités actuelles et futures de l\'IA dans SharePoint, (2) Vision stratégique pour l\'organisation, (3) Opportunités identifiées avec des cas d\'usage concrets, (4) Compréhension des exigences de préparation, (5) Considérations éthiques et de confidentialité, (6) Plan d\'action proposé.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];
